        ))}
      </div>
      <div style={{ marginTop:12, padding:10, background:'#0d2d1a', borderRadius:8, fontSize:12, color:'#9FE1CB' }}>📌 Desde out/2025 o ML usa ROAS como métrica principal.</div>
    </div>
  );
